import React from 'react';

const AdMoreServiceSection: React.FC = () => {
  return (
    <div className="px-4 py-12 max-w-6xl mx-auto space-y-12">
      {/* Section Title */}
      <div className="text-center space-y-4">
        <h1 className="text-4xl font-bold">AdMore 서비스 안내</h1>
        <p className="text-gray-600 text-lg">
          실제 사용자 기반의 안전하고 효과적인 검색 유입 서비스
        </p>
      </div>

      {/* 진행 방식 */}
      <section>
        <h2 className="text-2xl font-semibold mb-4">✅ 진행 방식</h2>
        <ul className="list-disc pl-6 space-y-2 text-gray-700">
          <li>유입을 원하는 URL 전달 → 실제 유입 시작</li>
          <li>키워드 설정 → 사용자 검색 기반 방문</li>
          <li>실제 사용자 기반 PC/모바일 방문으로 안정적인 진행</li>
        </ul>
      </section>

      {/* 서비스 특징 */}
      <section>
        <h2 className="text-2xl font-semibold mb-6">🌐 AdMore 서비스 특징</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {[
            { title: "실제 사용자 기반 유입", desc: "IP 조작 없이 기기 기반 유입" },
            { title: "한국 트래픽 기본 제공", desc: "요청 시 해외 트래픽도 가능" },
            { title: "SEO 최적화 효과", desc: "키워드 기반 노출 및 순위 향상" },
            { title: "애널리틱스 반영", desc: "Google/네이버 통계에서도 반영" },
            { title: "지속적인 상담 제공", desc: "단발성이 아닌 피드백 기반 관리" },
          ].map((item, i) => (
            <div key={i} className="bg-white rounded-lg shadow-md p-6 border border-gray-200">
              <h3 className="font-semibold text-lg mb-2">{item.title}</h3>
              <p className="text-gray-600">{item.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* 패키지 구성 */}
      <section>
        <h2 className="text-2xl font-semibold mb-6">📦 트래픽 유입 패키지</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[
            {
              name: "스탠다드",
              days: "10일",
              price: "10,000원",
              features: ["검색 키워드 기반 유입", "기본 SEO 최적화"]
            },
            {
              name: "디럭스",
              days: "20일",
              price: "18,000원",
              features: ["검색 노출 강화", "사이트별 전략 가능"]
            },
            {
              name: "프리미엄",
              days: "30일",
              price: "25,000원",
              features: ["장기 SEO 전략", "맞춤 키워드 제공"]
            }
          ].map((pkg, i) => (
            <div key={i} className="bg-white rounded-lg shadow-md p-6 border border-gray-200">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-xl font-semibold">{pkg.name}</h3>
                <span className="bg-orange-100 text-orange-800 text-xs font-medium px-2.5 py-0.5 rounded-full">
                  {pkg.days}
                </span>
              </div>
              <p className="text-2xl font-bold text-orange-600 mb-4">{pkg.price}</p>
              <ul className="list-disc pl-4 text-gray-600 space-y-1">
                {pkg.features.map((f, idx) => (
                  <li key={idx}>{f}</li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </section>

      {/* FAQ */}
      <section>
        <h2 className="text-2xl font-semibold mb-4">💬 자주 묻는 질문</h2>
        <div className="space-y-4">
          {[
            {
              q: "저품질 위험은 없나요?",
              a: "실제 사용자 기반 유입으로 품질 저하 위험이 없습니다."
            },
            {
              q: "유입 시작 시점은 언제인가요?",
              a: "결제 후 평균 24시간 이내 유입이 시작됩니다."
            },
            {
              q: "세금계산서 발행 가능한가요?",
              a: "법인사업자로 세금계산서 발행이 가능합니다."
            },
          ].map((item, i) => (
            <div key={i} className="bg-white rounded-lg shadow-md border border-gray-200">
              <details className="group">
                <summary className="flex items-center justify-between p-6 cursor-pointer hover:bg-gray-50">
                  <span className="font-semibold text-gray-900">{item.q}</span>
                  <span className="text-gray-400 group-open:rotate-180 transition-transform">
                    ▼
                  </span>
                </summary>
                <div className="px-6 pb-6 text-gray-600">
                  {item.a}
                </div>
              </details>
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="text-center pt-8">
        <p className="text-lg mb-4 text-gray-700">결제 전 상담을 통해 정확한 유입 전략을 받아보세요.</p>
        <button className="bg-orange-600 text-white px-6 py-3 rounded-md hover:bg-orange-700 transition duration-300 font-semibold">
          상담 요청하기
        </button>
      </section>
    </div>
  );
};

export default AdMoreServiceSection;
